function monitorEventLoop(threshold) {
  if (threshold === undefined) threshold = 50;
  var lastCheck = Date.now();
  setInterval(function() {
    var now = Date.now();
    var lag = now - lastCheck - 1000;
    if (lag > threshold) {
      console.warn("Event loop lag: " + lag + "ms");
    }
    lastCheck = now;
  }, 1000);
}

function blockLoop(ms) {
  var start = Date.now();
  while (Date.now() - start < ms) {}
}

monitorEventLoop();
blockLoop(2000);

